    {
        CTRL |= 1u << 26u;
    }

    /**
     * Clear CTRL's NEXTPREV_CLKDIV_RESTART bit.
     *
     * Write 1 to restart the clock dividers of state machines in neighbouring
     * PIO blocks, as specified by NEXT_PIO_MASK and PREV_PIO_MASK in the same
     * write.
     *
     *                             This is equivalent to writing 1 to the
     * corresponding CLKDIV_RESTART bits in those PIOs' CTRL registers.
     */
    inline void clear_CTRL_NEXTPREV_CLKDIV_RESTART() volatile
    {
        CTRL &= ~(1u << 26u);
    }

    /**
     * Toggle CTRL's NEXTPREV_CLKDIV_RESTART bit.
     *
     * Write 1 to restart the clock dividers of state machines in neighbouring
     * PIO blocks, as specified by NEXT_PIO_MASK and PREV_PIO_MASK in the same
     * write.
     *
     *                             This is equivalent to writing 1 to the
     * corresponding CLKDIV_RESTART bits in those PIOs' CTRL registers.
     */
    inline void toggle_CTRL_NEXTPREV_CLKDIV_RESTART() volatile
    {
        CTRL ^= 1u << 26u;
    }

    /**
     * Set all of CTRL's bit fields.
     *
     * (read-write) PIO control register
     */
    inline void set_CTRL(uint8_t SM_ENABLE, uint8_t SM_RESTART,
                         uint8_t CLKDIV_RESTART, uint8_t PREV_PIO_MASK,
                         uint8_t NEXT_PIO_MASK, bool NEXTPREV_SM_ENABLE,
                         bool NEXTPREV_SM_DISABLE,
                         bool NEXTPREV_CLKDIV_RESTART) volatile
    {
        uint32_t curr = CTRL;

        curr &= ~(0xfu);
        curr |= (SM_ENABLE & 0xfu);
        curr &= ~(0xfu << 4u);
        curr |= (SM_RESTART & 0xfu) << 4u;
        curr &= ~(0xfu << 8u);
        curr |= (CLKDIV_RESTART & 0xfu) << 8u;
        curr &= ~(0xfu << 16u);
        curr |= (PREV_PIO_MASK & 0xfu) << 16u;
        curr &= ~(0xfu << 20u);
        curr |= (NEXT_PIO_MASK & 0xfu) << 20u;
        curr &= ~(0b1u << 24u);
        curr |= (NEXTPREV_SM_ENABLE & 0b1u) << 24u;
        curr &= ~(0b1u << 25u);
        curr |= (NEXTPREV_SM_DISABLE & 0b1u) << 25u;
        curr &= ~(0b1u << 26u);
        curr |= (NEXTPREV_CLKDIV_RESTART & 0b1u) << 26u;

        CTRL = curr;
    }

