    /**
     * Get all of SM0_SHIFTCTRL's bit fields.
     *
     * (read-write) Control behaviour of the input/output shift registers for
     * state machine 0
     */
    inline void get_SM0_SHIFTCTRL(uint8_t &IN_COUNT, bool &FJOIN_RX_GET,
                                  bool &FJOIN_RX_PUT, bool &AUTOPUSH,
                                  bool &AUTOPULL, bool &IN_SHIFTDIR,
                                  bool &OUT_SHIFTDIR, uint8_t &PUSH_THRESH,
                                  uint8_t &PULL_THRESH, bool &FJOIN_TX,
                                  bool &FJOIN_RX) volatile
    {
        uint32_t curr = SM0_SHIFTCTRL;

        IN_COUNT = curr & 0b11111u;
        FJOIN_RX_GET = curr & (1u << 14u);
        FJOIN_RX_PUT = curr & (1u << 15u);
        AUTOPUSH = curr & (1u << 16u);
        AUTOPULL = curr & (1u << 17u);
        IN_SHIFTDIR = curr & (1u << 18u);
        OUT_SHIFTDIR = curr & (1u << 19u);
        PUSH_THRESH = (curr >> 20u) & 0b11111u;
        PULL_THRESH = (curr >> 25u) & 0b11111u;
        FJOIN_TX = curr & (1u << 30u);
        FJOIN_RX = curr & (1u << 31u);
    }

    /**
     * Set all of SM0_SHIFTCTRL's bit fields.
     *
     * (read-write) Control behaviour of the input/output shift registers for
     * state machine 0
     */
    inline void set_SM0_SHIFTCTRL(uint8_t IN_COUNT, bool FJOIN_RX_GET,
                                  bool FJOIN_RX_PUT, bool AUTOPUSH,
                                  bool AUTOPULL, bool IN_SHIFTDIR,
                                  bool OUT_SHIFTDIR, uint8_t PUSH_THRESH,
                                  uint8_t PULL_THRESH, bool FJOIN_TX,
                                  bool FJOIN_RX) volatile
    {
        uint32_t curr = SM0_SHIFTCTRL;

        curr &= ~(0b11111u);
        curr |= (IN_COUNT & 0b11111u);
        curr &= ~(0b1u << 14u);
        curr |= (FJOIN_RX_GET & 0b1u) << 14u;
        curr &= ~(0b1u << 15u);
        curr |= (FJOIN_RX_PUT & 0b1u) << 15u;
        curr &= ~(0b1u << 16u);
        curr |= (AUTOPUSH & 0b1u) << 16u;
        curr &= ~(0b1u << 17u);
        curr |= (AUTOPULL & 0b1u) << 17u;
        curr &= ~(0b1u << 18u);
        curr |= (IN_SHIFTDIR & 0b1u) << 18u;
        curr &= ~(0b1u << 19u);
        curr |= (OUT_SHIFTDIR & 0b1u) << 19u;
        curr &= ~(0b11111u << 20u);
        curr |= (PUSH_THRESH & 0b11111u) << 20u;
        curr &= ~(0b11111u << 25u);
        curr |= (PULL_THRESH & 0b11111u) << 25u;
        curr &= ~(0b1u << 30u);
        curr |= (FJOIN_TX & 0b1u) << 30u;
        curr &= ~(0b1u << 31u);
        curr |= (FJOIN_RX & 0b1u) << 31u;

        SM0_SHIFTCTRL = curr;
    }

